182	func buildReframerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
183		type failureEntry struct {
184			Summary string `json:"summary"`
185			Body    string `json:"body,omitempty"`
186		}
187		type envelope struct {
188			Title          string         `json:"title"`
189			Description    string         `json:"description"`
190			Acceptance     string         `json:"acceptance"`
191			FailureHistory []failureEntry `json:"failure_history"`
192		}
193	
194		env := envelope{
195			Title:       strings.TrimSpace(b.Title),
196			Description: strings.TrimSpace(b.Description),
197			Acceptance:  strings.TrimSpace(b.Acceptance),
198		}
199	
200		if events, err := store.Events(b.ID); err == nil {
201			for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
202				ev := events[i]
203				switch ev.Kind {
204				case "bead.result", "execute-bead", "per-bead-budget-exhausted":
205				default:
206					continue
207				}
208				env.FailureHistory = append(env.FailureHistory, failureEntry{
209					Summary: strings.TrimSpace(ev.Summary),
210					Body:    strings.TrimSpace(ev.Body),
211				})
212			}
213		}
214	
215		body, err := json.MarshalIndent(env, "", "  ")
216		if err != nil {
217			return "", fmt.Errorf("reframer: encode prompt: %w", err)
218		}
219	
220		var sb strings.Builder
221		sb.WriteString("MODE: reframe\n")
222		sb.WriteString("You are rewriting a bead's description and acceptance criteria after repeated execution failures.\n")
223		sb.WriteString("Your goal is to produce a clearer, more specific, implementation-ready bead.\n")
224		sb.WriteString("Preservation rules: governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, dependency IDs (ddx-XXXXXXXX), and NON-SCOPE bullets must appear in any rewrite.\n")
225		sb.WriteString("Return exactly one JSON object: {\"description\": string|null, \"acceptance\": string|null}\n")
226		sb.WriteString("Use null to leave a field unchanged. At least one field must be non-null and meaningfully changed.\n")
227		sb.WriteString("Do not include prose or markdown; return only the JSON object.\n\n")
228		sb.WriteString("```json\n")
229		sb.Write(body)
230		sb.WriteString("\n```\n")
231		return sb.String(), nil
232	}
