200	func validateAndApplyPreClaimIntakeRewrite(original *bead.Bead, rewrite PreClaimIntakeRewrite) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, []string, error) {
201		errOut := func(msg string, args ...any) (PreClaimIntakeRewrite, preClaimIntakeRewriteSnapshot, preClaimIntakeRewriteSnapshot, []string, error) {
202			return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, nil, fmt.Errorf(msg, args...)
203		}
204	
205		if original == nil {
206			return errOut("pre-claim intake rewrite: bead required")
207		}
208	
209		normalized := PreClaimIntakeRewrite{
210			Description:   strings.TrimSpace(rewrite.Description),
211			Acceptance:    strings.TrimSpace(rewrite.Acceptance),
212			ChangedFields: normalizePreClaimIntakeRewriteFields(rewrite.ChangedFields),
213		}
214		if len(normalized.ChangedFields) == 0 {
215			return errOut("pre-claim intake rewrite: missing changed_fields")
216		}
217	
218		allowed := map[string]struct{}{
219			"description": {},
220			"acceptance":  {},
221		}
222		for _, field := range normalized.ChangedFields {
223			if _, ok := allowed[field]; !ok {
224				return errOut("pre-claim intake rewrite: unsafe field %q", field)
225			}
226		}
227	
228		before := snapshotPreClaimIntakeRewrite(original.Description, original.Acceptance)
229	
230		var preservation []string
231		oldDescription := strings.TrimSpace(original.Description)
232		if hasString(normalized.ChangedFields, "description") {
233			if normalized.Description == "" {
234				return errOut("pre-claim intake rewrite: description rewrite missing")
235			}
236			if strings.EqualFold(strings.TrimSpace(normalized.Description), oldDescription) {
237				return errOut("pre-claim intake rewrite: description unchanged")
238			}
239			ev, err := validateDescriptionReplacement(oldDescription, normalized.Description)
240			if err != nil {
241				return PreClaimIntakeRewrite{}, preClaimIntakeRewriteSnapshot{}, preClaimIntakeRewriteSnapshot{}, nil, err
242			}
243			preservation = ev
244		} else if normalized.Description != "" {
245			return errOut("pre-claim intake rewrite: description supplied without changed_fields")
246		}
247	
248		oldAcceptance := strings.TrimSpace(original.Acceptance)
249		if hasString(normalized.ChangedFields, "acceptance") {
250			if normalized.Acceptance == "" {
251				return errOut("pre-claim intake rewrite: acceptance rewrite missing")
252			}
253			if strings.EqualFold(strings.TrimSpace(normalized.Acceptance), oldAcceptance) {
254				return errOut("pre-claim intake rewrite: acceptance unchanged")
255			}
256			if !acceptancePreservesCriteria(oldAcceptance, normalized.Acceptance) {
257				return errOut("pre-claim intake rewrite: acceptance criteria dropped or altered")
258			}
259		} else if normalized.Acceptance != "" {
260			return errOut("pre-claim intake rewrite: acceptance supplied without changed_fields")
261		}
262	
263		afterDescription := oldDescription
264		if containsString(normalized.ChangedFields, "description") {
265			afterDescription = normalized.Description
266		}
267		afterAcceptance := oldAcceptance
268		if containsString(normalized.ChangedFields, "acceptance") {
269			afterAcceptance = normalized.Acceptance
270		}
271		after := snapshotPreClaimIntakeRewrite(afterDescription, afterAcceptance)
272		return normalized, before, after, preservation, nil
273	}
