275	func snapshotPreClaimIntakeRewrite(description, acceptance string) preClaimIntakeRewriteSnapshot {
276		return preClaimIntakeRewriteSnapshot{
277			DescriptionBytes: len(description),
278			AcceptanceBytes:  len(acceptance),
279			DescriptionSHA:   hashText(description),
280			AcceptanceSHA:    hashText(acceptance),
281		}
282	}
283	
284	func hashText(text string) string {
285		sum := sha256.Sum256([]byte(text))
286		return hex.EncodeToString(sum[:])
287	}
288	
289	// acceptancePreservesCriteria returns true when the rewritten acceptance field
290	// ("after") contains all verifiable assertions from the original ("before").
291	//
292	// Structural reformatting — renumbering ("AC1." → "1."), reordering,
293	// normalising whitespace, or splitting one unnumbered sentence into several
294	// numbered criteria — is treated as preserving the criteria, not dropping them.
295	//
296	// A drop is detected only when the original had parseable numbered criteria and
297	// one or more of those criteria bodies are absent from the rewrite.
298	//
299	// When the original has no parseable numbered criteria (e.g. a single vague
300	// sentence), any rewrite that adds structured numbered criteria is accepted as
301	// an expansion; a rewrite that only rephrases the same prose content is checked
302	// by full-text containment.
303	func acceptancePreservesCriteria(before, after string) bool {
304		beforeCriteria := parseAcceptanceCriteria(before)
305		afterCriteria := parseAcceptanceCriteria(after)
306	
307		// If the original had no parseable numbered criteria, use a lenient path:
308		// any rewrite that introduces numbered criteria is an expansion (always
309		// accepted). If the rewrite is also unstructured, fall back to full-text
310		// containment on the normalised bodies.
311		if len(beforeCriteria) == 0 {
312			if len(afterCriteria) > 0 {
313				// Unstructured original → structured rewrite: expansion always allowed.
314				return true
315			}
316			normBefore := normalizeWhitespace(strings.TrimSpace(before))
317			normAfter := normalizeWhitespace(strings.TrimSpace(after))
318			if normBefore == "" {
319				return true
320			}
321			return strings.Contains(normAfter, normBefore)
322		}
323	
324		// Original had structured numbered criteria. Require each criterion body to
325		// appear in at least one criterion body of the rewrite (either verbatim or
326		// as a substring). The count check is a fast early-exit: if fewer criteria
327		// are present in the rewrite there must be a drop.
328		if len(afterCriteria) == 0 {
329			// Rewrite lost all structure — fall back to full-text containment of
330			// each criterion body inside the normalised rewrite text.
331			normAfter := normalizeWhitespace(strings.TrimSpace(after))
332			for _, criterion := range beforeCriteria {
333				if !strings.Contains(normAfter, criterion) {
334					return false
335				}
336			}
337			return true
338		}
339	
340		if len(afterCriteria) < len(beforeCriteria) {
341			return false
342		}
343	
344		for _, criterion := range beforeCriteria {
345			found := false
346			for _, candidate := range afterCriteria {
347				if strings.Contains(candidate, criterion) {
348					found = true
349					break
350				}
351			}
352			if !found {
353				return false
354			}
355		}
356		return true
