370	// parseAcceptanceCriterionBody extracts the verifiable assertion text from a
371	// single acceptance criterion line. It recognises common bullet-prefix
372	// conventions used in bead acceptance fields:
373	//
374	//   - Pure numeric:  "1. body"  "42. body"
375	//   - AC-prefix:     "AC1. body"  "AC2. body"  (letters then digits before ".")
376	//   - Dash/bullet:   "- body"  "• body"  "* body"
377	//
378	// All these forms are normalised so that a reformat (e.g. "AC1." → "1.") does
379	// not appear to have dropped a criterion when the assertion text is identical.
380	func parseAcceptanceCriterionBody(line string) (string, bool) {
381		trimmed := strings.TrimSpace(line)
382		if trimmed == "" {
383			return "", false
384		}
385	
386		// Dash/star/bullet prefix: "- body", "* body", "+ body", "• body"
387		// The bullet character (•, U+2022) is multi-byte in UTF-8, so we use
388		// HasPrefix rather than a byte switch for that case.
389		if len(trimmed) >= 2 {
390			switch trimmed[0] {
391			case '-', '*', '+':
392				body := normalizeWhitespace(trimmed[1:])
393				if body != "" {
394					return body, true
395				}
396			}
397		}
398		if strings.HasPrefix(trimmed, "•") {
399			body := normalizeWhitespace(strings.TrimPrefix(trimmed, "•"))
400			if body != "" {
401				return body, true
402			}
403		}
404	
405		dot := strings.Index(trimmed, ".")
406		if dot <= 0 {
407			return "", false
408		}
409		prefix := trimmed[:dot]
410	
411		// Pure numeric: "1.", "42."
412		if allDigits(prefix) {
413			body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
414			if body != "" {
415				return body, true
416			}
417			return "", false
418		}
419	
420		// AC-prefix: letters immediately followed by digits before the dot.
421		// Matches "AC1", "AC12", "A1", etc.
422		if isAlphaNumericBullet(prefix) {
423			body := normalizeWhitespace(strings.TrimSpace(trimmed[dot+1:]))
424			if body != "" {
425				return body, true
426			}
427			return "", false
428		}
429	
430		return "", false
431	}
432	
433	// isAlphaNumericBullet returns true when s looks like a labelled-list prefix
434	// of the form letters+digits (e.g. "AC1", "AC12", "A1"). At least one letter
435	// and one digit must be present; the digits must all trail the letters.
436	func isAlphaNumericBullet(s string) bool {
437		if s == "" {
438			return false
439		}
440		// Find the split point where letters end and digits begin.
441		splitAt := -1
442		for i, r := range s {
443			isLetter := (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z')
444			isDigit := r >= '0' && r <= '9'
445			if !isLetter && !isDigit {
446				return false
447			}
448			if isDigit && splitAt == -1 {
449				splitAt = i
450			}
451			if isLetter && splitAt != -1 {
452				// letter after digit — not a clean ACN prefix
453				return false
454			}
455		}
456		// Must have at least one letter (splitAt > 0) and at least one digit.
457		return splitAt > 0
458	}
